      const minimumWidth = derivePredictedTextWidthFloor(
        numeric(prediction && prediction.size) || getTemplateTextSize(node),
        charCount,
        targetLineCount,
        role
      );
      if (minimumWidth > 0) {
        targetWidth = targetWidth > 0 ? Math.max(targetWidth, minimumWidth) : minimumWidth;
      }
