      16;
    const renderedFontSize = getTemplateTextSize(renderedNode) || sourceFontSize;
    const preferredGapRatio = resolvePreferredTextGapRatio(textLayoutGuidance, previousRole, nextRole);
    const ratioGap =
      sourceFontSize > 0 && renderedFontSize > 0
