    if (role === "meta") {
      return Math.max(160, Math.round(contentWidth * 0.86));
    }
    if (role === "cta") {
      return Math.max(150, Math.round(contentWidth * 0.72));
    }
    return Math.max(180, Math.round(contentWidth * 0.94));
